{"content": "     1|import { create } from 'zustand';
     2|import { persist } from 'zustand/middleware';
     3|
     4|export interface CartItem {
     5|  id: string;
     6|  name: string;
     7|  price: number;
     8|  quantity: number;
     9|  image_url?: string;
    10|  max_stock?: number;
    11|}
    12|
    13|interface CartState {
    14|  items: CartItem[];
    15|  addItem: (item: Omit<CartItem, 'quantity'>) => void;
    16|  removeItem: (id: string) => void;
    17|  updateQuantity: (id: string, quantity: number) => void;
    18|  clearCart: () => void;
    19|  totalItems: () => number;
    20|  totalPrice: () => number;
    21|}
    22|
    23|export const useCartStore = create<CartState>()(
    24|  persist(
    25|    (set, get) => ({
    26|      items: [],
    27|
    28|      addItem: (item) => {
    29|        set((state) => {
    30|          const existingItem = state.items.find((i) => i.id === item.id);
    31|          if (existingItem) {
    32|            return {
    33|              items: state.items.map((i) =>
    34|                i.id === item.id
    35|                  ? {
    36|                      ...i,
    37|                      quantity: Math.min(
    38|                        i.quantity + 1,
    39|                        i.max_stock ?? Infinity,
    40|                      ),
    41|                    }
    42|                  : i,
    43|              ),
    44|            };
    45|          }
    46|          return { items: [...state.items, { ...item, quantity: 1 }] };
    47|        });
    48|      },
    49|
    50|      removeItem: (id) => {
    51|        set((state) => ({
    52|          items: state.items.filter((i) => i.id !== id),
    53|        }));
    54|      },
    55|
    56|      updateQuantity: (id, quantity) => {
    57|        set((state) => ({
    58|          items:
    59|            quantity <= 0
    60|              ? state.items.filter((i) => i.id !== id)
    61|              : state.items.map((i) => (i.id === id ? { ...i, quantity } : i)),
    62|        }));
    63|      },
    64|
    65|      clearCart: () => set({ items: [] }),
    66|
    67|      totalItems: () => {
    68|        return get().items.reduce((total, item) => total + item.quantity, 0);
    69|      },
    70|
    71|      totalPrice: () => {
    72|        return get().items.reduce(
    73|          (total, item) => total + item.price * item.quantity,
    74|          0,
    75|        );
    76|      },
    77|    }),
    78|    {
    79|      name: 'fun4me-cart',
    80|    },
    81|  ),
    82|);
    83|", "total_lines": 82, "file_size": 2015, "truncated": false, "is_binary": false, "is_image": false}

{"content": "     1|import { CURRENCY } from '@/lib/constants';
     2|
     3|/**
     4| * Formats a number as Paraguayan Guaraníes (₲)
     5| * Guaraníes don't use decimal places
     6| *
     7| * @example formatPrice(150000) => "₲ 150.000"
     8| * @example formatPrice(1500000) => "₲ 1.500.000"
     9| */
    10|export function formatPrice(amount: number): string {
    11|  const formatted = new Intl.NumberFormat('es-PY', {
    12|    style: 'decimal',
    13|    minimumFractionDigits: 0,
    14|    maximumFractionDigits: 0,
    15|  }).format(amount);
    16|
    17|  return `${CURRENCY.symbol} ${formatted}`;
    18|}
    19|
    20|/**
    21| * Formats a number as compact Guaraníes for display
    22| *
    23| * @example formatPriceCompact(1500000) => "₲ 1,5M"
    24| */
    25|export function formatPriceCompact(amount: number): string {
    26|  if (amount >= 1_000_000) {
    27|    const millions = amount / 1_000_000;
    28|    return `${CURRENCY.symbol} ${millions.toFixed(1).replace('.', ',')}M`;
    29|  }
    30|  if (amount >= 1_000) {
    31|    const thousands = amount / 1_000;
    32|    return `${CURRENCY.symbol} ${thousands.toFixed(0)}K`;
    33|  }
    34|  return formatPrice(amount);
    35|}
    36|
    37|/**
    38| * Parse a price string back to number
    39| */
    40|export function parsePrice(priceString: string): number {
    41|  const cleaned = priceString.replace(/[^\d]/g, '');
    42|  return parseInt(cleaned, 10) || 0;
    43|}
