{"content": "     1|import { WHATSAPP_NUMBER } from '@/lib/constants';
     2|import type { CartItem } from '@/lib/store/cart';
     3|import { formatPrice } from '@/lib/utils/format';
     4|
     5|/**
     6| * Generates a WhatsApp link with a pre-filled message
     7| */
     8|export function generateWhatsAppLink(message: string): string {
     9|  const encodedMessage = encodeURIComponent(message);
    10|  const cleanNumber = WHATSAPP_NUMBER.replace(/[^0-9]/g, '');
    11|  return `https://wa.me/${cleanNumber}?text=${encodedMessage}`;
    12|}
    13|
    14|/**
    15| * Generates a WhatsApp order message from cart items
    16| */
    17|export function generateOrderMessage(
    18|  items: CartItem[],
    19|  customerName?: string,
    20|): string {
    21|  const header = '🛒 *Nuevo Pedido - Fun4Me Store*\n\n';
    22|  const customerLine = customerName ? `👤 *Cliente:* ${customerName}\n\n` : '';
    23|
    24|  const itemLines = items
    25|    .map(
    26|      (item, index) =>
    27|        `${index + 1}. ${item.name}\n   Cantidad: ${item.quantity} | Precio: ${formatPrice(item.price * item.quantity)}`,
    28|    )
    29|    .join('\n\n');
    30|
    31|  const total = items.reduce(
    32|    (sum, item) => sum + item.price * item.quantity,
    33|    0,
    34|  );
    35|  const totalLine = `\n\n💰 *Total: ${formatPrice(total)}*`;
    36|
    37|  return `${header}${customerLine}${itemLines}${totalLine}`;
    38|}
    39|
    40|/**
    41| * Generates a WhatsApp link for placing an order
    42| */
    43|export function generateOrderWhatsAppLink(
    44|  items: CartItem[],
    45|  customerName?: string,
    46|): string {
    47|  const message = generateOrderMessage(items, customerName);
    48|  return generateWhatsAppLink(message);
    49|}
