}

// Extended category type with emoji
export interface ExtendedCategory extends Category {
  emoji?: string | null;
}

// Kink category (not in typed schema, accessed via `as any`)
export interface KinkCategory {
  id: string;
  created_at: string;
  name: string;
  slug: string;
  description: string | null;
  emoji: string | null;
  sort_order: number;
  is_active: boolean;
}
